As an AI text model, I cannot directly render or display a 3D image or video file. However, I can provide you with the **complete code** to generate a 3D house model instantly using **Three.js**, a powerful JavaScript library for 3D graphics on the web.

You can copy the code below, save it as an `.html` file (e.g., `house.html`), and open it in any modern web browser to see the rendered 3D house.

### 3D House Model Code (Three.js)

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>3D House Model</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: Arial, sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">3D House Model - Use Mouse to Rotate/Zoom</div>

    <!-- Import Three.js from CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 10, 20);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        document.body.appendChild(renderer.domElement);

        // 2. Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // 3. Ground
        const groundGeometry = new THREE.PlaneGeometry(100, 100);
        const groundMaterial = new THREE.MeshStandardMaterial({ color: 0x90EE90 });
        const ground = new THREE.Mesh(groundGeometry, groundMaterial);
        ground.rotation.x = -Math.PI / 2;
        ground.receiveShadow = true;
        scene.add(ground);

        // 4. House Construction Function
        function createHouse(x, z) {
            const houseGroup = new THREE.Group();
            houseGroup.position.set(x, 0, z);

            // Materials
            const wallMaterial = new THREE.MeshStandardMaterial({ color: 0xffffff });
            const roofMaterial = new THREE.MeshStandardMaterial({ color: 0x8B4513 });
            const windowMaterial = new THREE.MeshStandardMaterial({ color: 0x87CEEB });

            // Base
            const baseGeo = new THREE.BoxGeometry(6, 3, 6);
            const base = new THREE.Mesh(baseGeo, wallMaterial);
            base.position.y = 1.5;
            base.castShadow = true;
            base.receiveShadow = true;
            houseGroup.add(base);

            // Roof
            const roofGeo = new THREE.ConeGeometry(5, 3, 4);
            const roof = new THREE.Mesh(roofGeo, roofMaterial);
            roof.position.y = 4.5;
            roof.rotation.y = Math.PI / 4;
            roof.castShadow = true;
            houseGroup.add(roof);

            // Windows
            const windowGeo = new THREE.BoxGeometry(1.5, 1.5, 0.2);
            const window1 = new THREE.Mesh(windowGeo, windowMaterial);
            window1.position.set(1.5, 2, 2.9);
            window1.castShadow = false;
            houseGroup.add(window1);

            const window2 = new THREE.Mesh(windowGeo, windowMaterial);
            window2.position.set(-1.5, 2, 2.9);
            window2.castShadow = false;
            houseGroup.add(window2);

            // Door
            const doorGeo = new THREE.BoxGeometry(1.5, 2.5, 0.2);
            const doorMat = new THREE.MeshStandardMaterial({ color: 0x8B4513 });
            const door = new THREE.Mesh(doorGeo, doorMat);
            door.position.set(0, 1.25, 2.9);
            door.castShadow = true;
            houseGroup.add(door);

            scene.add(houseGroup);
        }

        // Create two houses
        createHouse(0, 0);
        createHouse(8, -5);

        // 5. Controls
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;
        controls.dampingFactor = 0.05;
        controls.maxPolarAngle = Math.PI / 2 - 0.1; // Prevent going below ground

        // 6. Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle Window Resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
```

### How to use this:
1.  **Copy** the code block above.
2.  **Paste** it into a text editor (like Notepad, TextEdit, or VS Code).
3.  **Save** the file as `house.html`.
4.  **Double-click** the file to open it in your web browser (Chrome, Firefox, Safari, Edge).

### What this code does:
*   **Sets up a 3D Scene:** Creates a virtual world with a sky-blue background and fog.
*   **Builds Geometry:** Constructs a house using basic 3D shapes (Boxes for walls, Cone for the roof).
*   **Adds Details:** Includes windows, a door, and a second house in the distance to show depth.
*   **Lighting & Shadows:** Adds realistic lighting so the house casts shadows on the ground.
*   **Interactivity:** Allows you to click and drag to rotate the view, scroll to zoom, and right-click to pan.
